import React, { useState } from 'react';

const Contact = () => {
  const [form, setForm] = useState({ name: '', email: '', checkin: '', checkout: '', message: '' });
  const [submitted, setSubmitted] = useState(false);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setSubmitted(true);
    setTimeout(() => setSubmitted(false), 4000);
    setForm({ name: '', email: '', checkin: '', checkout: '', message: '' });
  };

  return (
    <>
      {/* CSS inside same file */}
      <style>{`
        .contact {
          padding: 100px 0;
          background: var(--warm-white);
        }

        .contact__header {
          margin-bottom: 60px;
        }

        .contact__header .section-title em {
          font-style: italic;
          color: var(--gold);
        }

        .contact__grid {
          display: grid;
          grid-template-columns: 1fr 1.4fr;
          gap: 60px;
          align-items: start;
        }

        .contact__info {
          display: flex;
          flex-direction: column;
          gap: 28px;
        }

        .contact__info-item {
          display: flex;
          gap: 16px;
          align-items: flex-start;
        }

        .info-icon {
          font-size: 1.2rem;
          flex-shrink: 0;
          margin-top: 2px;
          width: 36px;
          height: 36px;
          background: var(--sand);
          display: flex;
          align-items: center;
          justify-content: center;
          border-radius: 2px;
        }

        .contact__info-item h4 {
          font-family: 'Cormorant Garamond', serif;
          font-size: 1rem;
          color: var(--deep-teal);
          margin-bottom: 4px;
          font-weight: 600;
        }

        .contact__info-item p {
          font-size: 0.85rem;
          color: var(--text-mid);
          line-height: 1.6;
        }

        .contact__info-item .small {
          font-size: 0.75rem;
          color: var(--text-light);
          margin-top: 2px;
        }

        .contact__map {
          margin-top: 8px;
          overflow: hidden;
          border: 1px solid var(--border);
        }

        .contact__form-wrap {
          background: white;
          padding: 40px;
          border: 1px solid var(--border);
        }

        .contact__form-title {
          font-family: 'Cormorant Garamond', serif;
          font-size: 1.8rem;
          color: var(--deep-teal);
          margin-bottom: 28px;
          font-weight: 400;
        }

        .contact__success {
          background: #e8f5e9;
          color: #2e7d32;
          padding: 12px 16px;
          margin-bottom: 24px;
          font-size: 0.85rem;
          border-left: 3px solid #4caf50;
        }

        .contact__form {
          display: flex;
          flex-direction: column;
          gap: 20px;
        }

        .form-row {
          display: grid;
          grid-template-columns: 1fr 1fr;
          gap: 16px;
        }

        .form-group {
          display: flex;
          flex-direction: column;
          gap: 6px;
        }

        .form-group label {
          font-size: 0.72rem;
          font-weight: 500;
          letter-spacing: 0.1em;
          text-transform: uppercase;
          color: var(--text-mid);
        }

        .form-group input,
        .form-group textarea {
          width: 100%;
          padding: 12px 14px;
          border: 1px solid var(--border);
          border-radius: 0;
          background: var(--warm-white);
          font-family: 'Jost', sans-serif;
          font-size: 0.9rem;
          color: var(--text-dark);
          transition: border-color 0.3s ease;
          outline: none;
          -webkit-appearance: none;
        }

        .form-group input:focus,
        .form-group textarea:focus {
          border-color: var(--gold);
          background: white;
        }

        .form-group textarea {
          resize: vertical;
          min-height: 100px;
        }

        .contact__submit {
          width: 100%;
          padding: 16px;
          font-size: 0.8rem;
          margin-top: 4px;
        }

        @media (max-width: 900px) {
          .contact__grid {
            grid-template-columns: 1fr;
            gap: 40px;
          }
        }

        @media (max-width: 480px) {
          .form-row {
            grid-template-columns: 1fr;
          }

          .contact__form-wrap {
            padding: 24px;
          }
        }
      `}</style>

      {/* JSX unchanged */}
      <section id="contact" className="contact">
        <div className="container">
          <div className="contact__header">
            <span className="section-label">Get In Touch</span>
            <h2 className="section-title">
              Begin Your <em>Journey</em>
            </h2>
            <p className="section-subtitle">
              Our concierge team is ready to curate your perfect escape. Reach out and let us craft an experience tailored to you.
            </p>
          </div>

          <div className="contact__grid">
            <div className="contact__info">
              <div className="contact__info-item">
                <span className="info-icon">📍</span>
                <div>
                  <h4>Address</h4>
                  <p>North Malé Atoll, Maldives<br />South Asia, Indian Ocean</p>
                </div>
              </div>

              <div className="contact__info-item">
                <span className="info-icon">📞</span>
                <div>
                  <h4>Phone</h4>
                  <p>+960 123 456 789</p>
                  <p className="small">Available 24/7</p>
                </div>
              </div>

              <div className="contact__info-item">
                <span className="info-icon">✉️</span>
                <div>
                  <h4>Email</h4>
                  <p>reservations@sunsetresort.com</p>
                  <p className="small">Reply within 2 hours</p>
                </div>
              </div>

              <div className="contact__info-item">
                <span className="info-icon">🕐</span>
                <div>
                  <h4>Check-in / Check-out</h4>
                  <p>Check-in: 2:00 PM</p>
                  <p>Check-out: 11:00 AM</p>
                </div>
              </div>

              <div className="contact__map">
                <iframe
                  title="Sunset Resort Location"
                  src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d126743.56993408044!2d73.38498862167965!3d4.174994999999999!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3b3ff3f20ee39f8f%3A0x4c6b2a8a68b3a6b7!2sNorth%20Mal%C3%A9%20Atoll%2C%20Maldives!5e0!3m2!1sen!2s!4v1700000000000!5m2!1sen!2s"
                  width="100%"
                  height="220"
                  style={{ border: 0 }}
                  loading="lazy"
                />
              </div>
            </div>

            <div className="contact__form-wrap">
              <h3 className="contact__form-title">Make a Reservation</h3>

              {submitted && (
                <div className="contact__success">
                  ✓ Thank you! We'll contact you within 2 hours.
                </div>
              )}

              <form className="contact__form" onSubmit={handleSubmit}>
                <div className="form-row">
                  <div className="form-group">
                    <label>Full Name</label>
                    <input type="text" name="name" value={form.name} onChange={handleChange} required />
                  </div>

                  <div className="form-group">
                    <label>Email Address</label>
                    <input type="email" name="email" value={form.email} onChange={handleChange} required />
                  </div>
                </div>

                <div className="form-row">
                  <div className="form-group">
                    <label>Check-in Date</label>
                    <input type="date" name="checkin" value={form.checkin} onChange={handleChange} required />
                  </div>

                  <div className="form-group">
                    <label>Check-out Date</label>
                    <input type="date" name="checkout" value={form.checkout} onChange={handleChange} required />
                  </div>
                </div>

                <div className="form-group">
                  <label>Special Requests</label>
                  <textarea name="message" value={form.message} onChange={handleChange} />
                </div>

                <button type="submit" className="btn-primary contact__submit">
                  Send Reservation Request
                </button>
              </form>
            </div>
          </div>
        </div>
      </section>
    </>
  );
};

export default Contact;
